# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

import os
import json
import time
import secrets
import hashlib
from datetime import datetime, timedelta
from typing import Optional, Dict

from flask import Flask, request, jsonify
from flask_cors import CORS
from eth_account.messages import encode_defunct
from web3 import Web3
import jwt

app = Flask(__name__)
CORS(app)

# Configuration
SECRET_KEY = os.environ.get("JWT_SECRET_KEY", "your-secret-key-change-in-production")
NONCE_EXPIRY_SECONDS = 300  # 5 minutes
JWT_EXPIRY_HOURS = 24

# Initialize Web3
PROVIDER_URL = os.environ.get("WEB3_PROVIDER_URL", "https://mainnet.infura.io/v3/your-project-id")
w3 = Web3(Web3.HTTPProvider(PROVIDER_URL))

# In-memory stores (use Redis or a database in production)
nonce_store: Dict[str, dict] = {}  # address -> {nonce, created_at}
session_store: Dict[str, dict] = {}  # address -> {user data}
revoked_tokens: set = set()


class Web3AuthService:
    """Service for handling Web3 wallet authentication."""

    @staticmethod
    def generate_nonce(address: str) -> str:
        """Generate a unique nonce for a given wallet address."""
        address = Web3.to_checksum_address(address)
        nonce = secrets.token_hex(32)
        nonce_store[address.lower()] = {
            "nonce": nonce,
            "created_at": time.time(),
            "used": False,
        }
        return nonce

    @staticmethod
    def get_sign_message(address: str, nonce: str) -> str:
        """Construct the message that the user should sign."""
        return (
            f"Welcome to Web3 Auth!\n\n"
            f"Please sign this message to verify your wallet ownership.\n\n"
            f"Wallet: {address}\n"
            f"Nonce: {nonce}\n"
            f"Timestamp: {datetime.utcnow().isoformat()}\n\n"
            f"This signature will not trigger a blockchain transaction or cost any gas fees."
        )

    @staticmethod
    def verify_signature(address: str, message: str, signature: str) -> bool:
        """Verify that the signature was produced by the claimed address."""
        try:
            address = Web3.to_checksum_address(address)
            encoded_message = encode_defunct(text=message)
            recovered_address = w3.eth.account.recover_message(
                encoded_message, signature=signature
            )
            return recovered_address.lower() == address.lower()
        except Exception as e:
            print(f"Signature verification error: {e}")
            return False

    @staticmethod
    def verify_nonce(address: str, nonce: str) -> bool:
        """Verify that the nonce is valid and not expired."""
        address_lower = address.lower()
        if address_lower not in nonce_store:
            return False

        stored = nonce_store[address_lower]

        if stored["used"]:
            return False

        if stored["nonce"] != nonce:
            return False

        elapsed = time.time() - stored["created_at"]
        if elapsed > NONCE_EXPIRY_SECONDS:
            del nonce_store[address_lower]
            return False

        return True

    @staticmethod
    def consume_nonce(address: str):
        """Mark a nonce as used so it cannot be replayed."""
        address_lower = address.lower()
        if address_lower in nonce_store:
            nonce_store[address_lower]["used"] = True

    @staticmethod
    def generate_jwt(address: str) -> str:
        """Generate a JWT token for an authenticated user."""
        payload = {
            "sub": address.lower(),
            "address": Web3.to_checksum_address(address),
            "iat": datetime.utcnow(),
            "exp": datetime.utcnow() + timedelta(hours=JWT_EXPIRY_HOURS),
            "jti": secrets.token_hex(16),
        }
        return jwt.encode(payload, SECRET_KEY, algorithm="HS256")

    @staticmethod
    def verify_jwt(token: str) -> Optional[dict]:
        """Verify and decode a JWT token."""
        try:
            if token in revoked_tokens:
                return None
            payload = jwt.decode(token, SECRET_KEY, algorithms=["HS256"])
            return payload
        except jwt.ExpiredSignatureError:
            return None
        except jwt.InvalidTokenError:
            return None

    @staticmethod
    def get_or_create_user(address: str) -> dict:
        """Get or create a user record for the given address."""
        address_lower = address.lower()
        checksum_address = Web3.to_checksum_address(address)

        if address_lower not in session_store:
            session_store[address_lower] = {
                "address": checksum_address,
                "created_at": datetime.utcnow().isoformat(),
                "last_login": datetime.utcnow().isoformat(),
                "login_count": 0,
            }

        user = session_store[address_lower]
        user["last_login"] = datetime.utcnow().isoformat()
        user["login_count"] += 1
        return user


auth_service = Web3AuthService()


def require_auth(f):
    """Decorator to require JWT authentication on routes."""
    from functools import wraps

    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get("Authorization")
        if not auth_header or not auth_header.startswith("Bearer "):
            return jsonify({"error": "Missing or invalid authorization header"}), 401

        token = auth_header.split(" ")[1]
        payload = auth_service.verify_jwt(token)

        if not payload:
            return jsonify({"error": "Invalid or expired token"}), 401

        request.user = payload
        return f(*args, **kwargs)

    return decorated


def validate_eth_address(address: str) -> bool:
    """Validate an Ethereum address."""
    try:
        Web3.to_checksum_address(address)
        return True
    except (ValueError, TypeError):
        return False


# ─── Routes ───────────────────────────────────────────────────────────────────


@app.route("/api/auth/nonce", methods=["POST"])
def request_nonce():
    """
    Step 1: Client requests a nonce for their wallet address.
    The client will sign this nonce to prove wallet ownership.
    """
    data = request.get_json()
    if not data or "address" not in data:
        return jsonify({"error": "Wallet address is required"}), 400

    address = data["address"]

    if not validate_eth_address(address):
        return jsonify({"error": "Invalid Ethereum address"}), 400

    checksum_address = Web3.to_checksum_address(address)
    nonce = auth_service.generate_nonce(checksum_address)
    message = auth_service.get_sign_message(checksum_address, nonce)

    return jsonify({
        "address": checksum_address,
        "nonce": nonce,
        "message": message,
        "expires_in": NONCE_EXPIRY_SECONDS,
    }), 200


@app.route("/api/auth/verify", methods=["POST"])
def verify_signature():
    """
    Step 2: Client submits signed message. We verify the signature,
    recover the signing address, and issue a JWT if valid.
    """
    data = request.get_json()
    if not data:
        return jsonify({"error": "Request body is required"}), 400

    required_fields = ["address", "signature", "message", "nonce"]
    missing = [f for f in required_fields if f not in data]
    if missing:
        return jsonify({"error": f"Missing fields: {', '.join(missing)}"}), 400

    address = data["address"]
    signature = data["signature"]
    message = data["message"]
    nonce = data["nonce"]

    if not validate_eth_address(address):
        return jsonify({"error": "Invalid Ethereum address"}), 400

    # Verify the nonce is valid and not expired
    if not auth_service.verify_nonce(address, nonce):
        return jsonify({"error": "Invalid, expired, or already used nonce. Request a new one."}), 401

    # Verify the signature matches the claimed address
    if not auth_service.verify_signature(address, message, signature):
        return jsonify({"error": "Invalid signature. The recovered address does not match."}), 401

    # Consume the nonce to prevent replay attacks
    auth_service.consume_nonce(address)

    # Get or create user and generate JWT
    user = auth_service.get_or_create_user(address)
    token = auth_service.generate_jwt(address)

    return jsonify({
        "authenticated": True,
        "token": token,
        "token_type": "Bearer",
        "expires_in": JWT_EXPIRY_HOURS * 3600,
        "user": user,
    }), 200


@app.route("/api/auth/me", methods=["GET"])
@require_auth
def get_current_user():
    """Get the currently authenticated user's information."""
    address = request.user["address"]
    address_lower = address.lower()

    user = session_store.get(address_lower, {
        "address": address,
    })

    return jsonify({
        "authenticated": True,
        "user": user,
    }), 200


@app.route("/api/auth/refresh", methods=["POST"])
@require_auth
def refresh_token():
    """Refresh the JWT token for an authenticated user."""
    address = request.user["address"]

    # Revoke old token
    auth_header = request.headers.get("Authorization")
    old_token = auth_header.split(" ")[1]
    revoked_tokens.add(old_token)

    new_token = auth_service.generate_jwt(address)

    return jsonify({
        "token": new_token,
        "token_type": "Bearer",
        "expires_in": JWT_EXPIRY_HOURS * 3600,
    }), 200


@app.route("/api/auth/logout", methods=["POST"])
@require_auth
def logout():
    """Logout and revoke the current token."""
    auth_header = request.headers.get("Authorization")
    token = auth_header.split(" ")[1]
    revoked_tokens.add(token)

    return jsonify({"message": "Successfully logged out"}), 200


@app.route("/api/auth/verify-token", methods=["POST"])
def verify_token():
    """Verify if a JWT token is still valid (useful for other services)."""
    data = request.get_json()
    if not data or "token" not in data:
        return jsonify({"error": "Token is required"}), 400

    payload = auth_service.verify_jwt(data["token"])
    if payload:
        return jsonify({
            "valid": True,
            "address": payload["address"],
            "expires_at": payload["exp"],
        }), 200
    else:
        return jsonify({"valid": False}), 401


