def demo_auth_flow():
    """Demonstrate the full authentication flow locally."""
    from eth_account import Account

    print("=" * 60)
    print("Web3 Authentication Demo")
    print("=" * 60)

    # Create a test account
    account = Account.create()
    address = account.address
    print(f"\n1. Generated test wallet: {address}")

    # Step 1: Request nonce
    nonce = auth_service.generate_nonce(address)
    message = auth_service.get_sign_message(address, nonce)
    print(f"\n2. Generated nonce: {nonce[:20]}...")
    print(f"   Message to sign:\n{message}")

    # Step 2: Sign the message
    encoded_message = encode_defunct(text=message)
    signed = w3.eth.account.sign_message(encoded_message, private_key=account.key)
    signature = signed.signature.hex()
    print(f"\n3. Signed message. Signature: 0x{signature[:40]}...")

    # Step 3: Verify signature
    is_valid = auth_service.verify_signature(address, message, signed.signature.hex())
    print(f"\n4. Signature valid: {is_valid}")

    # Step 4: Verify nonce
    nonce_valid = auth_service.verify_nonce(address, nonce)
    print(f"   Nonce valid: {nonce_valid}")

    if is_valid and nonce_valid:
        auth_service.consume_nonce(address)
        user = auth_service.get_or_create_user(address)
        token = auth_service.generate_jwt(address)
        print(f"\n5. Authentication successful!")
        print(f"   JWT Token: {token[:50]}...")
        print(f"   User: {json.dumps(user, indent=2)}")

        # Verify JWT
        payload = auth_service.verify_jwt(token)
        print(f"\n6. JWT verification: {'valid' if payload else 'invalid'}")
        if payload:
            print(f"   Address from token: {payload['address']}")
    else:
        print("\n5. Authentication FAILED!")

    print("\n" + "=" * 60)


